final:
module JK_FF (  
    input J,  
    input K,  
    input CLK,  
    output reg Q  
);  
  wire _tap_J = J & {1{1'b1}};

    always @(posedge CLK) begin  
        if (J && !K)  
            Q <= 1;  
        else if (!J && K)  
            Q <= 0;  
        else if (J && K)  
            Q <= ~Q;  
    end  
endmodule
